import 'package:flutter_test/flutter_test.dart';
import 'package:integration_test/integration_test.dart';
import 'package:music_app/services/youtube_service.dart';
import 'package:music_app/services/lastfm_service.dart';

/// Integration test to evaluate YouTube + Last.fm matching quality.
///
/// Run with a Last.fm API key for full results:
///   flutter test integration_test/matching_test.dart \
///     --dart-define=LASTFM_API_KEY=your_key
///
/// Without a key, only YouTube-only results are shown.
void main() {
  IntegrationTestWidgetsFlutterBinding.ensureInitialized();

  late YouTubeService ytService;
  late LastFmService lfmService;

  // Queries covering different matching scenarios
  final queries = [
    'Bohemian Rhapsody Queen',       // classic, well-known
    'Bad Bunny',                     // artist-only, Spanish
    'Blinding Lights',               // song-only, no artist
    'Taylor Swift Anti-Hero',        // artist + song
    'despacito',                     // single word, Spanish
    'Kendrick Lamar HUMBLE',         // rap
    'Dua Lipa Levitating',           // pop
    'xzqwerty12345notareal',         // gibberish — should degrade gracefully
  ];

  setUp(() {
    ytService = YouTubeService();
    lfmService = LastFmService();
  });

  group('YouTube-only search quality', () {
    for (final query in queries) {
      testWidgets('query: "$query"', (tester) async {
        final results = await ytService.searchSongs(query);

        print('\n=== YouTube "$query" (${results.length} results) ===');
        for (final s in results.take(5)) {
          print('  [${s.id}] "${s.title}" — ${s.artist}');
        }

        // Structural assertions
        expect(results, isA<List>(), reason: 'should always return a list');
        if (query != 'xzqwerty12345notareal') {
          expect(results, isNotEmpty, reason: 'real query should return results');
          for (final s in results) {
            expect(s.id, isNotEmpty, reason: 'every song must have an id');
            expect(s.title, isNotEmpty, reason: 'every song must have a title');
            expect(s.artist, isNotEmpty, reason: 'every song must have an artist');
          }
        }
      });
    }
  });

  group('Last.fm-only search quality', () {
    for (final query in queries) {
      testWidgets('query: "$query"', (tester) async {
        final tracks = await lfmService.searchTracks(query, limit: 10);

        print('\n=== Last.fm "$query" (${tracks.length} results) ===');
        for (final t in tracks.take(5)) {
          print('  "${t.title}" — ${t.artist}');
        }

        expect(tracks, isA<List>(), reason: 'should always return a list');
      });
    }
  });

  group('Combined YouTube + Last.fm enrichment quality', () {
    for (final query in queries) {
      testWidgets('query: "$query"', (tester) async {
        // Fetch both in parallel
        final ytFuture = ytService.searchSongs(query);
        final lfmFuture = lfmService.searchTracks(query, limit: 30);
        final ytResults = await ytFuture;
        final lfmTracks = await lfmFuture;

        // Compute match rate: how many YT songs found a Last.fm counterpart
        int matched = 0;
        final matchDetails = <String>[];

        for (final song in ytResults) {
          final hit = lfmTracks.firstWhere(
            (t) => _titlesMatch(song.title, t.title) || _titlesMatch(song.artist, t.artist),
            orElse: () => (title: '', artist: '', imageUrl: ''),
          );
          if (hit.title.isNotEmpty) {
            matched++;
            matchDetails.add('  ✓ YT:"${song.title}/${song.artist}" → LFM:"${hit.title}/${hit.artist}"');
          } else {
            matchDetails.add('  ✗ YT:"${song.title}/${song.artist}" → no match');
          }
        }

