import 'dart:convert';
import 'package:http/http.dart' as http;
import '../models/music_models.dart';

class MusicServerService {
  static const _base = 'https://music-app-server-lupbg4y2ha-uc.a.run.app';
  final http.Client _client;

  MusicServerService({http.Client? client}) : _client = client ?? http.Client();

  /// Search songs via our server. Returns songs list (rank-ordered).
  /// Falls back to empty list on any error so caller can fall back to YouTube.
  Future<List<Song>> searchSongs(String query) async {
    try {
      final uri = Uri.parse('$_base/songs/search-youtube');
      final response = await _client
          .post(uri,
              headers: {'Content-Type': 'application/json'},
              body: jsonEncode({'query': query}))
          .timeout(const Duration(seconds: 10));

      if (response.statusCode != 200) {
        print('[MusicServer] search failed: ${response.statusCode}');
        return [];
      }

      final data = jsonDecode(response.body) as Map<String, dynamic>;
      final songs = data['songs'] as List? ?? [];
      final result = songs.map((s) => Song(
        id: s['youtubeId'] as String,
        title: s['title'] as String,
        artist: s['artistName'] as String,
        album: '',
        imageUrl: s['thumbnailUrl'] as String? ?? '',
        audioUrl: '',
        duration: Duration.zero,
      )).toList();

      print('[MusicServer] search "$query": ${result.length} songs');
      return result;
    } catch (e) {
      print('[MusicServer] search error: $e');
      return [];
    }
  }
}

