Future<void> _saveMeta(Song song, String localPath, {bool isAuto = false}) async {
  final prefs = await SharedPreferences.getInstance();
  final raw = prefs.getString(_metaKey);
  final list = raw != null ? List<Map<String, dynamic>>.from(jsonDecode(raw)) : <Map<String, dynamic>>[];
  list.removeWhere((e) => e['id'] == song.id);
  list.insert(0, {
    'id': song.id, 'title': song.title, 'artist': song.artist,
    'album': song.album, 'imageUrl': song.imageUrl,
    'audioUrl': localPath, 'duration': song.duration.inSeconds,
    'auto': isAuto,
  });

  // Evict oldest auto-downloaded entries beyond the cap
  if (isAuto) {
    final autoEntries = list.where((e) => e['auto'] == true).toList();
    if (autoEntries.length > maxAutoDownloads) {
      final toEvict = autoEntries.sublist(maxAutoDownloads);
      for (final entry in toEvict) {
        final path = entry['audioUrl'] as String?;
        if (path != null) await File(path).delete().catchError((_) => File(path));
        list.removeWhere((e) => e['id'] == entry['id']);
      }
      print('[Download] evicted ${toEvict.length} old auto-downloads');
    }
  }

  await prefs.setString(_metaKey, jsonEncode(list));
}

