    // Use pre-fetched suggestion
    final next = _suggestedSongs.first;
    _suggestedSongs = [];
    _queue.add(next);
    _currentIndex = _queue.length - 1;
    playSong(next);
  } else if (_currentSong != null) {
    // Fetch a new suggestion on demand
    _fetchAndPlaySuggestion();
  }
}

