_currentSong = song;
// Only reset queue and fire generatePlaylist when user taps a song (queue.length <= 1 or song not in current queue)
final songInQueue = _queue.any((s) => s.id == song.id);
if (!songInQueue) {
  _queue = [song];
  _currentIndex = 0;
  _isSeeding = false;
  _pendingSeedQueries = [];
  _usedSeedQueries.clear();

  // Fire generate-playlist in background — replaces queue when ready
  _youtubeService.generatePlaylist(song).then((playlist) {
    if (playlist.isEmpty) {
      print('[MusicPlayerProvider] generate-playlist returned empty for ${song.id}');
      return;
    }
    if (_currentSong?.id == song.id) {
      // Find the current song in the playlist to set correct index
      final idx = playlist.indexWhere((s) => s.id == song.id);
      _queue = playlist;
      _currentIndex = idx >= 0 ? idx : 0;
      print('[MusicPlayerProvider] queue updated: ${playlist.length} songs, currentIndex=$_currentIndex');
      notifyListeners();
    }
  });
} else {
  _currentIndex = _queue.indexWhere((s) => s.id == song.id);
}
notifyListeners();

